(window.webpackJsonp=window.webpackJsonp||[]).push([[37],{358:function(n,v,_){"use strict";_.r(v);var t=_(25),a=Object(t.a)({},(function(){var n=this,v=n._self._c;return v("ContentSlotsDistributor",{attrs:{"slot-key":n.$parent.slotKey}},[v("h1",{attrs:{id:"诗集"}},[v("a",{staticClass:"header-anchor",attrs:{href:"#诗集"}},[n._v("#")]),n._v(" 诗集")]),n._v(" "),v("h2",{attrs:{id:"文章"}},[v("a",{staticClass:"header-anchor",attrs:{href:"#文章"}},[n._v("#")]),n._v(" 文章")]),n._v(" "),v("ul",[v("li",[n._v("高适-燕歌行")]),n._v(" "),v("li",[n._v("曹植-洛神赋")]),n._v(" "),v("li",[n._v("白居易-长恨歌")]),n._v(" "),v("li",[n._v("白居易-琵琶行")]),n._v(" "),v("li",[n._v("张若虚-春江花月夜")]),n._v(" "),v("li",[n._v("杨玉环-赠张云容舞")]),n._v(" "),v("li",[n._v("王勃-滕王阁序")]),n._v(" "),v("li",[n._v("黄启元-春风秋水辞二首")])]),n._v(" "),v("h2",{attrs:{id:"杜甫-饮中八仙歌"}},[v("a",{staticClass:"header-anchor",attrs:{href:"#杜甫-饮中八仙歌"}},[n._v("#")]),n._v(" 杜甫-饮中八仙歌")]),n._v(" "),v("p",[n._v("知章骑马似乘船，眼花落井水底眠。汝阳三斗始朝天，\n道逢麹车口流涎，恨不移封向酒泉。左相日兴费万钱，\n饮如长鲸吸百川，衔杯乐圣称世贤。宗之潇洒美少年，\n举觞白眼望青天，皎如玉树临风前。苏晋长斋绣佛前，\n醉中往往爱逃禅。李白一斗诗百篇，长安市上酒家眠。\n天子呼来不上船，自称臣是酒中仙。张旭三杯草圣传，\n脱帽露顶王公前，挥毫落纸如云烟。焦遂五斗方卓然，\n高谈雄辨惊四筵。")]),n._v(" "),v("h2",{attrs:{id:"梁启超-中国少年说-节选"}},[v("a",{staticClass:"header-anchor",attrs:{href:"#梁启超-中国少年说-节选"}},[n._v("#")]),n._v(" 梁启超-中国少年说（节选）")]),n._v(" "),v("p",[n._v("红日初升，其道大光。河出伏流，一泻汪洋。潜龙腾渊，鳞爪飞扬。乳虎啸谷，百兽震惶。\n鹰隼试翼，风尘翕张。奇花初胎，矞矞皇皇。干将发硎，有作其芒。天戴其苍，地履其黄。\n纵有千古，横有八荒。前途似海，来日方长。美哉，我少年中国，与天不老！\n壮哉，我中国少年，与国无疆！")]),n._v(" "),v("h2",{attrs:{id:"名句摘录"}},[v("a",{staticClass:"header-anchor",attrs:{href:"#名句摘录"}},[n._v("#")]),n._v(" 名句摘录")]),n._v(" "),v("ul",[v("li",[n._v("心在山东身在吴，飘蓬江海谩嗟吁。他时若遂凌云志，敢笑黄巢不丈夫!宋江")]),n._v(" "),v("li",[n._v("待到秋来九月八，我花开后百花杀。冲天香气透长安，满城尽带黄金甲。黄巢")]),n._v(" "),v("li",[n._v("百花发时我不发，我若发时都吓杀。要与西风战一场，遍身穿就黄金甲。朱元璋")]),n._v(" "),v("li",[n._v("收拾残破废经营，暂驻商洛苦练兵。月夜偷看击剑晚，星晨风送马蹄轻。李自成")]),n._v(" "),v("li",[n._v("苍天已死，黄天当立，岁在甲子，天下大吉。张角")]),n._v(" "),v("li",[n._v("莫道石人一只眼，挑动黄河天下反。韩山童")])]),n._v(" "),v("p",[n._v("多闻草木少识人，常守自性清净心。我寻竹马旅尘埃 喜见梅花独自开。逢人不说人间事，便是人间无事人。\n//这是我对生活的期许和对自我的要求。我将继续走进大自然，寻找属于自己的那片净土，让心灵在草木的柔软中沉淀，让自己与大自然相互滋养，共同成长。\n//“多闻草木少识人 常守自性清净心”这句话表达了应该多关注自然界的草木，减少对人与人之间的关注。这是一种追求内心纯净和真实的表达方式。\n“我寻竹马旅尘埃 喜见梅花独自开”这句话则表达了寻找童年回忆的过程，并且很高兴地看到梅花在寒冷的冬季独自开放。这句话强调了对过去的怀念以及对自然界的欣赏。\n综合起来，这句话的含义是：应该多关注自然界的美好，减少对人际关系的关注，保持内心的纯净和真实，寻找童年的美好回忆，并在面对困难的时候寻找内心的安慰和喜悦。")]),n._v(" "),v("p",[n._v("宋 司马光 过故洛阳城 若问古今兴废事，请君只看洛阳城。\n明 袁崇焕 临刑口占 一生事业总成空，半世功名在梦中。\n清 边瑾 六十四屯遗迹在，何人光复大江东。\n十年驱驰海色寒，孤臣于此望宸銮。\n知我者，谓我心忧\n欲将心事付瑶琴，知音少，弦断有谁听。\n一朝春尽红颜老，花落人亡两不知。\n取次花丛懒回顾，半缘修道半缘君。\n溪云初起日沉阁，山雨欲来风满楼。\n花有重开日，人无再少年\n落花有意随流水，流水无心恋落花。\n年年岁岁花相似，岁岁年年人不同\n我本将心向明月，奈何明月照沟渠\n本是青灯不归客，却因浊酒恋红尘。\n埋骨何须桑梓地，人生无处不青山。\n我自狂歌空度日，飞扬跋扈为谁雄。\n一身转战三千里，一剑曾当百万师。\n我可对镜贴花黄，亦可铁甲披寒光。\n满堂花醉三千客，一剑霜寒十四州。\n水利万物而不争，多出三尺又如何。\n断头今日意如何？创业艰难百战多。\n此去泉台招旧部，旌旗十万斩阎罗。\n金鳞岂是池中物，一遇风云便化龙\n举世非之而不加沮\n不经一番寒彻骨，怎得梅花扑鼻香。\n大鹏一日同风起，扶摇直上九万里。\n清风若无拂我意，我自上天揽星辰。\n清风有意难留我，明月无心自照人。\n满堂花醉三千客，一剑霜寒十四州。\n上邪，作者不详，南风知我意，吹梦到西洲。君生我未生，我生君已老。千山空皓雪，万里尽黄沙。\n月儿弯弯照九州，几家欢乐几家愁。\n鲜衣怒马少年时，不负韶华行且知，少年自当扶摇上，揽星衔月逐日光\n紫陌红尘拂面来，无人不道看花回。玄都观里桃千树，尽是刘郎去后栽。")]),n._v(" "),v("p",[n._v("两人对酌山花开，一杯一杯复一杯。\n我醉欲眠卿且去，明朝有意抱琴来。")]),n._v(" "),v("p",[n._v("大明王朝，六公： 徐达，唐胜宗，李善长，冯胜，常遇春，邓愈\n力士脱靴，李白：云想衣裳花想容，春风拂槛露华浓。若非群玉山头见，会向瑶台月下逢。\n粗柳簸箕细柳斗，世上谁见（嫌）男儿丑\n本想吟诗震天下，奈何自己没文化\n军民团结如一人，试看天下谁能敌\n挽住云河洗天青，闽山闽水物华新。小梅正吐黄金蕊，老榕先掬碧玉新。\n君驭南风冬亦暖，我临东海情同深。难得举城作一庆，爱我人民爱我军。")]),n._v(" "),v("p",[n._v("自信人生二百年，会当水击三千里。")]),n._v(" "),v("p",[n._v("东方欲晓，莫道君行早。\n踏遍青山人未老，风景这边独好。\n会昌城外高峰，颠连直接东溟。\n战士指看南粤，更加郁郁葱葱。")]),n._v(" "),v("p",[n._v("无衣")]),n._v(" "),v("p",[n._v("人世无常，人情冷暖，奔忙一生，碌碌无为，然无奈悲苦之一生，若能遇见斗沙片刻\n之美好，也足以。")]),n._v(" "),v("p",[n._v("天下熙攘皆为利往，庙堂蝇营皆为名来")]),n._v(" "),v("p",[n._v("有论道天下之心，实无自证自辩之癖。")]),n._v(" "),v("p",[n._v("朝闻道 夕死可矣")]),n._v(" "),v("p",[n._v("敬那大争之世，敬这小酌之时。")]),n._v(" "),v("p",[n._v("名不显时心不朽，再挑灯火看文章。")]),n._v(" "),v("p",[n._v("我画兰江水悠悠，爱晚亭上枫叶愁。早已胸有成竹。")]),n._v(" "),v("p",[n._v("半醒半醉日复日，花醉花开年复年。")]),n._v(" "),v("p",[n._v("人生易老天难老，岁岁重阳。今又重阳，战地黄花分外香。\n一年一度秋风劲，不似春光。胜似春光，寥廓江天万里霜。")]),n._v(" "),v("p",[n._v("虽不周于今之人兮，愿依 彭咸 之遗则。")]),n._v(" "),v("p",[n._v("纵不周于今之人兮，亦不弃 吾之所往。")]),n._v(" "),v("p",[n._v("从此唯行乐，闲愁奈我何。\n心如止水鉴常明，见尽人生万物情。")]),n._v(" "),v("p",[n._v("凤凰台上凤凰游，凤去台空江自流。")]),n._v(" "),v("p",[n._v("桃花一簇开无主，可爱深红爱浅红。")]),n._v(" "),v("p",[n._v("自是花中第一流")]),n._v(" "),v("p",[n._v("大道如青天，我独不得出。\n羞逐长安社中儿，赤鸡白雉赌梨栗。(白雉 一作：白狗)\n弹剑作歌奏苦声，曳裾王门不称情。\n淮阴市井笑韩信，汉朝公卿忌贾生。\n君不见昔时燕家重郭隗，拥篲折节无嫌猜。\n剧辛乐毅感恩分，输肝剖胆效英才。\n昭王白骨萦蔓草，谁人更扫黄金台？\n行路难，归去来！")]),n._v(" "),v("p",[n._v("有耳莫洗颍川水，有口莫食首阳蕨。\n含光混世贵无名，何用孤高比云月？\n吾观自古贤达人，功成不退皆殒身。\n子胥既弃吴江上，屈原终投湘水滨。\n陆机雄才岂自保？李斯税驾苦不早。\n华亭鹤唳讵可闻？上蔡苍鹰何足道？\n君不见吴中张翰称达生，秋风忽忆江东行。\n且乐生前一杯酒，何须身后千载名？")]),n._v(" "),v("p",[n._v("来时形单，去时影只。\n天下熙熙，皆为利来；天下攘攘，皆为利往。\n压抑内心，想要追逐热爱的诗句。\n身处热闹之地，却无人知晓其热爱。\n人生短暂，不如追逐自己喜欢的。")]),n._v(" "),v("p",[n._v("依剑证道心通明，青衫磊落长歌行。\n奇门遁甲游四方，九星八门断吉凶。\n仙宝葫芦聚灵兽，乾坤凝练化神火。\n八卦灵镜控震雷，凛然正气荡妖魔。\n虚怀若谷尝百草，岐黄妙术展幡旗。\n祈符笔走通九幽，素手悬铃摄心魂。\n身负灵石行天下，冲关断喝辨正邪。\n仙籍经文誊卷上，日省三身驭鬼神。")])])}),[],!1,null,null,null);v.default=a.exports}}]);